import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Enhanced Ad Engagement Type Metrics","description":"","frontmatter":{"title":"Enhanced Ad Engagement Type Metrics","slug":"enhanced-ad-engagement-type-metrics"},"headers":[],"relativePath":"account-hub/enhanced-ad-engagement-type-metrics.md","filePath":"account-hub/enhanced-ad-engagement-type-metrics.md"}'),d={name:"account-hub/enhanced-ad-engagement-type-metrics.md"};function n(s,e,i,h,l,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<p>We&#39;ve added more engagement metrics support for a couple of partners! Get the details here 🎯</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch now supports <strong>engagement</strong> conversion metrics for ads on TikTok and Google Adwords. You&#39;ll now get more comprehensive insights and the ability to control the full range of available ad engagement touch types. Here is what this update brings:</p><ul><li>Touch subtype for TikTok for Business and Google Adwords is now available in the Branch Dashboard via <a href="./paid-ads-analytics.html">Ads Analytics</a>.</li><li>Touch subtype for TikTok for Business is now available in <a href="./apis-overview.html">Export APIs</a>.</li></ul><h3 id="engagement-type-support" tabindex="-1">Engagement Type Support <a class="header-anchor" href="#engagement-type-support" aria-label="Permalink to &quot;Engagement Type Support&quot;">​</a></h3><p><strong>Google Adwords</strong></p><table tabindex="0"><thead><tr><th>Engagement Type</th><th>Attribution Support</th></tr></thead><tbody><tr><td>Engaged View</td><td>Click-Through</td></tr></tbody></table><p><strong>TikTok For Business</strong></p><table tabindex="0"><thead><tr><th>Engagement Type</th><th>Attribution Support</th></tr></thead><tbody><tr><td>Engaged View</td><td>Click-Through</td></tr><tr><td>Engaged Click</td><td>Click-Through</td></tr><tr><td>Click to Store</td><td>Click-Through</td></tr><tr><td>View</td><td>View-Through</td></tr></tbody></table><h2 id="what-does-it-look-like" tabindex="-1">What does it look like? <a class="header-anchor" href="#what-does-it-look-like" aria-label="Permalink to &quot;What does it look like?&quot;">​</a></h2><h3 id="dashboard-report" tabindex="-1">Dashboard Report <a class="header-anchor" href="#dashboard-report" aria-label="Permalink to &quot;Dashboard Report&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Compare By</p><p>Use the <code>touch subtype</code> metric to view your engagement attribution</p></div><h3 id="exports" tabindex="-1">Exports <a class="header-anchor" href="#exports" aria-label="Permalink to &quot;Exports&quot;">​</a></h3><p>Either through Dashboard Custom Exports or Data, utilize the following:</p><table tabindex="0"><thead><tr><th>Export Type</th><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Dashboard Custom Exports</td><td>Column</td><td>Touch Subtype</td></tr><tr><td>Custom Exports API</td><td><code>fields</code></td><td><code>last_attributed_touch_data_tilde_touch_subtype</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Looking to learn more about TikTok For Business or Google Adwords? View our respective guides here:</p><ul><li><a href="./tiktok-for-business.html">TikTok For Business</a></li><li><a href="./google-ads.html">Google Adwords</a></li></ul></div><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h4 id="what-are-the-video-ad-view-thresholds-for-each-partner-to-be-counted-as-an-engaged-view" tabindex="-1">What are the video ad view thresholds for each partner to be counted as an engaged view? <a class="header-anchor" href="#what-are-the-video-ad-view-thresholds-for-each-partner-to-be-counted-as-an-engaged-view" aria-label="Permalink to &quot;What are the video ad view thresholds for each partner to be counted as an engaged view?&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Ad Partner</th><th>Definition</th></tr></thead><tbody><tr><td><a href="https://ads.tiktok.com/help/article/about-engaged-view-through-attribution" target="_blank" rel="noreferrer">TikTok for Business</a></td><td>When someone watches a video ad for more than <strong>six seconds</strong></td></tr><tr><td><a href="https://support.google.com/google-ads/answer/10048752" target="_blank" rel="noreferrer">Google Adwords</a></td><td>When someone watches a video ad for more than <strong>ten seconds</strong></td></tr></tbody></table>',19)])])}const g=t(d,[["render",n]]);export{u as __pageData,g as default};
